VARIANT_SUFFIXES = [
    ("", None),
    ("უფლებამოსილმა პირმა საპირისპირო მოქმედება შეასრულა და საქმე სამართლებრივ შეფასებაზე გადავიდა.", "რომელი პასუხი ასახავს სწორ სამართლებრივ შედეგს?"),
    ("მხარემ ამ გარემოებაზე დაყრდნობით განსხვავებული განმარტება შესთავაზა ბიუროს.", "რომელი განმარტება შეესაბამება კანონს?"),
    ("გადაწყვეტილების პროექტში საჭიროა მოკლე დასაბუთების ჩამოყალიბება.", "რომელი დასაბუთება უნდა ჩაიწეროს?"),
]


def make_rows() -> list[dict[str, str]]:
    raw: list[dict[str, str]] = []
    for addon, override_prompt in VARIANT_SUFFIXES:
        for case in CASES:
            if len(raw) >= 200:
                break
            prompt = override_prompt or case["prompt"]
            text = f"{case['scenario']} {addon} {LAW} შესაბამისად, {prompt}".replace("  ", " ")
            raw.append(
                {
                    **case,
                    "text": text,
                }
            )
        if len(raw) >= 200:
            break
    raw = raw[:200]

    rows: list[dict[str, str]] = []
    for idx, case in enumerate(raw):
        correct_option = "ABCD"[idx % 4]
        options = list(case["wrongs"])
        options.insert(idx % 4, case["correct"])
        rows.append(
            {
                "category_slug": "criminal",
                "subcategory_slug": "probation",
                "text": case["text"],
                "difficulty": case["difficulty"],
                "explanation": f"სწორი პასუხია {correct_option}, რადგან {LAW} {case['article']} ადგენს: {case['correct']}",
                "law_name": LAW,
                "law_article": case["article"],
                "source_url": "",
                "law_version_date": VERSION_DATE,
                "is_prime": "false",
                "option_a": options[0],
                "option_b": options[1],
                "option_c": options[2],
                "option_d": options[3],
                "correct_option": correct_option,
            }
        )
    return rows


def validate(rows: list[dict[str, str]]) -> None:
    if len(rows) != 200:
        raise ValueError(f"Expected 200 rows, got {len(rows)}")
    seen_text = set()
    for i, row in enumerate(rows, start=1):
        if row["text"] in seen_text:
            raise ValueError(f"Duplicate question text at row {i}")
        seen_text.add(row["text"])
        if LAW not in row["text"]:
            raise ValueError(f"Missing law name in question at row {i}")
        options = [row["option_a"], row["option_b"], row["option_c"], row["option_d"]]
        if len(set(options)) != 4:
            raise ValueError(f"Non-unique options at row {i}")
        correct_index = "ABCD".index(row["correct_option"])
        if not options[correct_index]:
            raise ValueError(f"Empty correct option at row {i}")
        if not row["explanation"].startswith(f"სწორი პასუხია {row['correct_option']}"):
            raise ValueError(f"Bad explanation at row {i}")


rows = make_rows()
validate(rows)

with OUT.open("w", encoding="utf-8", newline="") as f:
    writer = csv.DictWriter(f, fieldnames=HEADER)
    writer.writeheader()
    writer.writerows(rows)

articles = [{"law_article": case["article"], "title": case["title"]} for case in CASES]
write_sql(rows, articles)
print(len(rows))
